// Fetch full analytics data for this post from Supabase
// (LinkedIn Marketing API requires partner access - using stored metrics instead)
const postId = $input.item.json.post_id || 'unknown';
const url = 'https://zshmlgtvhdneekbfcyjc.supabase.co/rest/v1/content_posts?post_id=eq.' + encodeURIComponent(postId) + '&select=*';

let postData = $input.item.json;
try {
  const response = await $http.get(url, {
    headers: {
      'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InpzaG1sZ3R2aGRuZWVrYmZjeWpjIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3Mjc5NzI4OSwiZXhwIjoyMDg4MzczMjg5fQ.Jop1GNUQijVBzV8KEYLfgpdkdS8b-KhwHFtNY2kH23Y',
