    }
  });
  if (Array.isArray(response.data) && response.data.length > 0) {
    postData = { ...postData, ...response.data[0] };
  }
} catch(e) {
  // Use existing data if fetch fails
}

return {
  post_id: postData.post_id || postId,
  content_pillar: postData.content_pillar || 'unknown',
  post_content: postData.post_content || '',
  post_length: postData.post_length || 0,
  impressions: postData.impressions || 0,
  clicks: postData.clicks || 0,
  likes: postData.likes || 0,
  comments: postData.comments || 0,
  shares: postData.shares || 0,
  engagement_rate: postData.engagement_rate || 0,
  analytics_updated_at: postData.analytics_updated_at || null,
  created_at: postData.created_at || new Date().toISOString()
};

