const supabaseUrl = 'https://zshmlgtvhdneekbfcyjc.supabase.co';
const serviceKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InpzaG1sZ3R2aGRuZWVrYmZjeWpjIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3Mjc5NzI4OSwiZXhwIjoyMDg4MzczMjg5fQ.Jop1GNUQijVBzV8KEYLfgpdkdS8b-KhwHFtNY2kH23Y';
const sevenDaysAgo = new Date(Date.now() - 7*24*60*60*1000).toISOString();
try {
  const response = await $http.get(supabaseUrl + '/rest/v1/prospects?created_at=gte.' + sevenDaysAgo + '&select=*', { headers: { 'apikey': serviceKey, 'Authorization': 'Bearer ' + serviceKey } });
  const prospects = Array.isArray(response) ? response : (response.data || []);
  return [{ json: { total_prospects: prospects.length, new_this_week: prospects.length, week_start: sevenDaysAgo } }];
} catch(e) {
  return [{ json: { total_prospects: 0, new_this_week: 0, week_start: sevenDaysAgo } }];
}

// Fetch engagement activities from last 7 days
const since = new Date(Date.now() - 7*24*60*60*1000).toISOString();
const url = 'https://zshmlgtvhdneekbfcyjc.supabase.co/rest/v1/engagement_activities?created_at=gte.' + since + '&select=*';
let data = [];
try {
